#include <stdio.h>
#include <stdlib.h>
#define MOD 998244353

long long powmod(long long a, long long b) {
    long long res = 1;
    while (b > 0) {
        if (b & 1) res = (res * a) % MOD;
        a = (a * a) % MOD;
        b >>= 1;
    }
    return res;
}

int main() {
    int k, m, n;
    scanf("%d %d", &k, &m);
    scanf("%d", &n);
    long long p = 0;
    long long q = 1;
    for (int i = 0; i < n; i++) {
        int a, b, c;
        scanf("%d %d %d", &a, &b, &c);
        long long sum = 0;
        for (int j = a; j <= b; j++) {
            sum = (sum + powmod(j, k)) % MOD;
        }
        sum = (sum * c) % MOD;
        sum = (sum * powmod(b - a + 1, MOD - 2)) % MOD;
        p = (p + sum) % MOD;
        q = (q * powmod(b - a + 1, c)) % MOD;
    }
    long long q_inv = powmod(q, MOD - 2);
    printf("%lld\n", (p * q_inv) % MOD);
    return 0;
}

