import java.util.Scanner;

public class Main {
    static final long MOD = 998244353;

    public static long powmod(long a, long b) {
        long res = 1;
        while (b > 0) {
            if (b % 2 == 1) res = (res * a) % MOD;
            a = (a * a) % MOD;
            b >>= 1;
        }
        return res;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int k = sc.nextInt();
        int m = sc.nextInt();
        int n = sc.nextInt();
        long p = 0;
        long q = 1;
        for (int i = 0; i < n; i++) {
            int a = sc.nextInt();
            int b = sc.nextInt();
            int c = sc.nextInt();
            long sum = 0;
            for (int j = a; j <= b; j++) {
                sum = (sum + powmod(j, k)) % MOD;
            }
            sum = (sum * c) % MOD;
            sum = (sum * powmod(b - a + 1, MOD - 2)) % MOD;
            p = (p + sum) % MOD;
